int factorial(int input) {
  int n = input;
  if ((n <= 1)) {
    return 1;
  }
  return (n * factorial((n - 1)));
}

int fibonacci(int input) {
  int n = input;
  if ((n < 2)) {
    return n;
  }
  return (fibonacci((n - 1)) + fibonacci((n - 2)));
}

